import { useNavigate } from "react-router-dom";
import { useAuth } from "../../Context/AuthContext";
import './Settings.css';
import { useEffect } from "react";

function Settings() {
    const {isAuthenticated, user} = useAuth();
    const navigate = useNavigate();
    useEffect(()=>{
        if (!isAuthenticated){
            navigate("/");
        }
    })

    return (
        <>
        <div className="settings-page-container">
            <div className="settings-container">
                <div className="header-container">
                    <p className="account-settings">Account Settings</p>
                    <p className="info-message">Manage your profile information and security.</p>
                </div>
                <div className="profile-info-container">
                    <div className="profile-header">
                        Profile Information
                    </div>
                    <div className="profile-username">
                        <div className="profile-username-left">
                            <div className="profile-username-header">
                                Username
                            </div>
                            <div className="profile-username-text">
                                {user.username}
                            </div>
                        </div>
                        <div className="profile-username-right">
                            <button>Change Username</button>
                        </div>
                    </div>
                    <div className="profile-email">
                        <div className="profile-email-left">
                            <div className="profile-email-header">
                                Email Address
                            </div>
                            <div className="profile-email-text">
                                {user.email}
                            </div>
                        </div>
                        <div className="profile-email-right">
                            <button>Change Email</button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        </>
    )
};

export default Settings;
